/*!id: eclipse.jdt.ui.javaplugin.getpluginpreferences.to.instancescope*/
/*!description: Replace deprecated JavaPlugin.getPluginPreferences() with InstanceScope.INSTANCE.getNode(JavaPlugin.getPluginId()) to migrate from old Preferences API.*/
/*!severity: info*/
org.eclipse.jdt.internal.ui.JavaPlugin.getPluginPreferences() :: inClass("org.eclipse.jdt.internal.ui.JavaPlugin")
=> org.eclipse.core.runtime.preferences.InstanceScope.INSTANCE.getNode(org.eclipse.jdt.internal.ui.JavaPlugin.getPluginId())
;;

/*!id: eclipse.jdt.ui.preferences.setvalue.to.put*/
/*!description: Replace Preferences.setValue() with IEclipsePreferences.put() for deprecated API migration.*/
/*!severity: info*/
$preferences.setValue($key, $value) :: instanceof($preferences, "org.eclipse.core.runtime.Preferences")
=> ((org.eclipse.core.runtime.preferences.IEclipsePreferences)$preferences).put($key, $value)
;;

/*!id: eclipse.jdt.ui.preferences.getstring.to.getwithdefault*/
/*!description: Replace Preferences.getString() with IEclipsePreferences.get() providing a default value for deprecated API migration.*/
/*!severity: info*/
$preferences.getString($key) :: instanceof($preferences, "org.eclipse.core.runtime.Preferences")
=> ((org.eclipse.core.runtime.preferences.IEclipsePreferences)$preferences).get($key, "")
;;

